function ModelGM:DebugGMListResp(pb,ret)
	if(ret ~= 0) then return end
	local pbClone = LProtoHelper.ProtoToPureTable(pb)
	self._commandList = pbClone.commandList
	self._bGmOpen = self._commandList and #self._commandList > 0 or false
